'use client';

import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import { motion } from 'framer-motion';
import { Calendar, User, ArrowRight } from 'lucide-react';
import { Button } from '@/components/ui/button';

const articles = [
    {
        category: "Design",
        title: "The Architecture of Silence: Inside Kyoto's Newest Ryokan",
        excerpt: "How minimalism and shadow play create the ultimate sanctuary for the modern traveler.",
        author: "Elena Fisher",
        date: "Oct 24, 2025",
        image: "https://images.unsplash.com/photo-1503899036084-c55cdd92da26?q=80",
    },
    {
        category: "Destinations",
        title: "Hidden Amalfi: Beyond the Tourist Trail",
        excerpt: "Discovering secret coves and family-run trattorias in Italy's most glamorous coastline.",
        author: "Marco Rossi",
        date: "Oct 18, 2025",
        image: "https://images.unsplash.com/photo-1533105079780-92b9be482077?q=80",
    },
    {
        category: "Lifestyle",
        title: "Pack Like a Pro: The Nomad's Guide to Luggage",
        excerpt: "Essential gear for the global citizen who refuses to check a bag.",
        author: "Sarah Jenkins",
        date: "Oct 12, 2025",
        image: "https://images.unsplash.com/photo-1553531384-cc64ac80f931?q=80",
    },
    {
        category: "Food & Drink",
        title: "Tokyo's Midnight Diners",
        excerpt: "Where the best chefs eat when their shifts end.",
        author: "Kenji Tanaka",
        date: "Sep 30, 2025",
        image: "https://images.unsplash.com/photo-1559339352-11d035aa65de?q=80",
    }
];

export default function JournalPage() {
    return (
        <div className="min-h-screen bg-black text-white selection:bg-amber-500/30 font-sans">
            <Navbar />

            <section className="pt-40 pb-20 px-6">
                <div className="max-w-7xl mx-auto">
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="mb-20"
                    >
                        <span className="text-accent-gold font-bold tracking-[0.3em] uppercase text-sm mb-4 block">The RoamFast Journal</span>
                        <h1 className="text-6xl md:text-8xl font-bold font-heading mb-8">
                            Stories from <br /><span className="text-gradient-neo">The Road</span>
                        </h1>
                    </motion.div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-20">
                        {articles.map((article, i) => (
                            <motion.article
                                key={article.title}
                                initial={{ opacity: 0, y: 30 }}
                                whileInView={{ opacity: 1, y: 0 }}
                                viewport={{ once: true }}
                                transition={{ delay: i * 0.1 }}
                                className="group cursor-pointer"
                            >
                                <div className="rounded-[32px] overflow-hidden mb-8 relative aspect-[4/3]">
                                    <div className="absolute inset-0 bg-black/20 group-hover:bg-black/0 transition-colors z-10" />
                                    <img
                                        src={article.image}
                                        alt={article.title}
                                        className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                                    />
                                    <span className="absolute top-6 left-6 z-20 bg-white/10 backdrop-blur-md px-4 py-2 rounded-full text-xs font-bold uppercase tracking-wider border border-white/10">
                                        {article.category}
                                    </span>
                                </div>

                                <div className="space-y-4">
                                    <div className="flex items-center gap-6 text-sm text-slate-400">
                                        <div className="flex items-center gap-2">
                                            <User className="w-4 h-4 text-accent-gold" />
                                            {article.author}
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Calendar className="w-4 h-4 text-accent-gold" />
                                            {article.date}
                                        </div>
                                    </div>

                                    <h2 className="text-3xl font-bold font-heading group-hover:text-accent-gold transition-colors leading-tight">
                                        {article.title}
                                    </h2>
                                    <p className="text-slate-400 text-lg leading-relaxed line-clamp-2">
                                        {article.excerpt}
                                    </p>

                                    <div className="pt-4">
                                        <Button variant="link" className="p-0 text-white group-hover:text-accent-gold text-lg font-bold">
                                            Read Story <ArrowRight className="w-5 h-5 ml-2 group-hover:translate-x-2 transition-transform" />
                                        </Button>
                                    </div>
                                </div>
                            </motion.article>
                        ))}
                    </div>
                </div>
            </section>

            <Footer />
        </div>
    );
}
